import { createElement, type HTMLAttributes } from 'react'
import { cn } from '../utils/cn'

const headingStyles = {
  h1: 'font-heading font-light text-brand-h1 text-navy',
  h2: 'font-heading font-light text-brand-h2 text-navy',
  h3: 'font-heading font-medium text-brand-h3 text-navy',
  h4: 'font-heading font-medium text-brand-h4 text-navy',
} as const

export type HeadingLevel = keyof typeof headingStyles

export type HeadingProps = HTMLAttributes<HTMLHeadingElement> & {
  level: HeadingLevel
}

export function Heading({ level, className, ...props }: HeadingProps) {
  return createElement(level, {
    className: cn(headingStyles[level], className),
    ...props,
  })
}

const textStyles = {
  body: 'font-body text-body text-foreground',
  bodySm: 'font-body text-body-sm text-muted',
  lead: 'font-body text-lead text-foreground',
  leadLg: 'font-body text-lead-lg text-foreground',
  leadXl: 'font-body text-lead-xl text-foreground',
  muted: 'font-body text-body text-muted',
} as const

export type TextVariant = keyof typeof textStyles

export type TextProps = HTMLAttributes<HTMLParagraphElement> & {
  variant?: TextVariant
  as?: 'p' | 'span'
}

export function Text({ variant = 'body', as = 'p', className, ...props }: TextProps) {
  return createElement(as, {
    className: cn(textStyles[variant], className),
    ...props,
  })
}
