import type { HTMLAttributes } from 'react'
import { cn } from '../utils/cn'

export type CardVariant = 'brand' | 'feature' | 'plain'

export type CardProps = HTMLAttributes<HTMLDivElement> & {
  variant: CardVariant
}

export function Card({ variant, className, children, ...props }: CardProps) {
  if (variant === 'brand') {
    return (
      <div
        className={cn(
          'rounded-brand border border-lightGrey bg-lightGrey transition duration-[250ms] ease-in-out',
          'hover:-translate-y-1 hover:shadow-card-hover',
          className,
        )}
        {...props}
      >
        {children}
      </div>
    )
  }

  if (variant === 'feature') {
    return (
      <div
        className={cn('overflow-hidden rounded-brand border border-border bg-white', className)}
        {...props}
      >
        {children}
      </div>
    )
  }

  return (
    <div className={cn('rounded-brand border border-border bg-transparent', className)} {...props}>
      {children}
    </div>
  )
}
