import { cn } from '../utils/cn'

export type AccordionToggleIconProps = {
  isOpen: boolean
  className?: string
}

/** Closed: green circle + white strokes; open: surface gray fill + navy strokes. */
export function AccordionToggleIcon({ isOpen, className }: AccordionToggleIconProps) {
  return (
    <span className={cn('block h-6 w-6 shrink-0', className)} aria-hidden="true">
      <svg viewBox="0 0 24 24" className="h-6 w-6">
        <rect
          width="24"
          height="24"
          rx="12"
          className={cn(
            'fill-current',
            isOpen ? 'text-surface' : 'text-[var(--color-accordion-green)]',
          )}
        />
        <path
          d="M7.5 12h9"
          fill="none"
          stroke="currentColor"
          strokeWidth="1.8"
          strokeLinecap="round"
          className={isOpen ? 'text-navy' : 'text-white'}
        />
        {!isOpen ? (
          <path
            d="M12 7.5v9"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.8"
            strokeLinecap="round"
            className="text-white"
          />
        ) : null}
      </svg>
    </span>
  )
}
