import type { HTMLAttributes } from 'react'
import { cn } from '../utils/cn'

export type ChipProps = HTMLAttributes<HTMLSpanElement>

export function Chip({ className, children, ...props }: ChipProps) {
  return (
    <span
      className={cn(
        'inline-flex items-center rounded-full border border-border bg-lightGrey px-3 py-1 font-body text-xs text-muted md:text-sm',
        className,
      )}
      {...props}
    >
      {children}
    </span>
  )
}
