import { forwardRef } from 'react'
import type { ButtonHTMLAttributes } from 'react'
import { GeniusStripHoverBg } from './GeniusStripHoverBg'
import { cn } from '../utils/cn'

export type ButtonVariant =
  | 'primaryPill'
  | 'secondaryPill'
  | 'solidAccent'
  | 'ghost'
  | 'outlineOnDark'

export type ButtonProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  variant: ButtonVariant
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(function Button(
  { variant, className, children, type = 'button', ...props },
  ref,
) {
  if (variant === 'primaryPill') {
    return (
      <button
        ref={ref}
        type={type}
        className={cn(
          'group inline-flex items-center justify-center focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-navy focus-visible:ring-offset-2',
          className,
        )}
        {...props}
      >
        <div className="relative cursor-pointer overflow-hidden rounded-pill bg-navy">
          <GeniusStripHoverBg />
          <span className="relative z-20 block rounded-pill px-[36px] py-[15px] text-center text-[17px] font-heading font-medium leading-none text-white transition-colors duration-300 ease-in-out sm:px-12 md:py-[1.0625rem]">
            {children}
          </span>
        </div>
      </button>
    )
  }

  if (variant === 'secondaryPill') {
    return (
      <button
        ref={ref}
        type={type}
        className={cn(
          'group inline-flex items-center justify-center focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-navy focus-visible:ring-offset-2',
          className,
        )}
        {...props}
      >
        <div className="relative cursor-pointer overflow-hidden rounded-pill bg-navy/5">
          <GeniusStripHoverBg />
          <span className="relative z-20 block rounded-pill px-4 py-2.5 text-center font-heading text-xs font-medium leading-none text-navy transition-colors duration-300 ease-in-out group-hover:text-white sm:px-6 sm:py-3 sm:text-sm md:px-8 md:py-3.5 lg:px-5 lg:py-[0.8rem] lg:text-[1rem]">
            {children}
          </span>
        </div>
      </button>
    )
  }

  if (variant === 'solidAccent') {
    return (
      <button
        ref={ref}
        type={type}
        className={cn(
          'inline-flex items-center justify-center rounded-md bg-accent px-5 py-2.5 text-base font-medium text-white transition-colors hover:bg-accent-hover focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent/70',
          className,
        )}
        {...props}
      >
        {children}
      </button>
    )
  }

  if (variant === 'ghost') {
    return (
      <button
        ref={ref}
        type={type}
        className={cn(
          'rounded-md px-2 py-1 text-sm font-medium text-muted transition-colors hover:bg-lightGrey hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent/70',
          className,
        )}
        {...props}
      >
        {children}
      </button>
    )
  }

  /* outlineOnDark */
  return (
    <button
      ref={ref}
      type={type}
      className={cn(
        'inline-flex items-center justify-center rounded-md border border-white/30 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-white/10 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white/50',
        className,
      )}
      {...props}
    >
      {children}
    </button>
  )
})
